// // This module implements an asynchronous FIFO buffer with a depth of 16,384 and a width of 12 bits.
module top_module(douta,
    addra,
    clka,
    dina,
    wea);output reg [11:0] douta;
  input [13:0] addra;
  input clka;
  input [11:0] dina;
  input wea;

  reg [11:0] mem [0:16383];

  always @(posedge clka) begin
    if(wea) begin
      mem[addra] <= dina;
    end else begin
      douta <= mem[addra];
    end
  end
endmodule
